      // Function to display car subsections
      function displayCarSubsections(category, containerId) {
        const carSubsections = document.getElementById(containerId);
        carSubsections.classList.remove('show'); // Hide with transition

        setTimeout(() => {
          carSubsections.innerHTML = ''; // Clear previous content

          const cars = carData[category] || [];
          cars.forEach(car => {
            const carElement = document.createElement('div');
            
            carElement.className = 'car-card fade-in-up';
            carElement.innerHTML = `
              <img src="${car.image}" alt="${car.name}" class="car-card-img">
              <div class="car-card-body">
                <h3>${car.name}</h3>
                <p class="text-accent" style="margin-bottom: 0.5rem; font-weight: 600;">${car.price}</p>
                <button class="btn btn-primary" style="width: 100%;" onclick="window.location.href='model-details?model=${car.name}'">View Details</button>
              </div>
            `;
            carSubsections.appendChild(carElement);
          });

          carSubsections.classList.add('show'); // Show with transition
        }, 700); // Match the increased transition duration
      }

      // Add event listeners to selection buttons
      document.querySelectorAll('.selection-button').forEach(button => {
        button.addEventListener('click', () => {
          document.querySelectorAll('.selection-button').forEach(btn => btn.classList.remove('active'));
          button.classList.add('active');
          const category = button.getAttribute('data-category');
          const containerId = button.closest('.section').querySelector('.car-subsections').id;
          displayCarSubsections(category, containerId);
        });
      });

      // Display default category (SUV) on page load
      document.querySelector('.selection-button[data-category="suv"]').classList.add('active');
      displayCarSubsections('suv', 'car-subsections');

      // Display default category (1-4-lakh) on page load for cars-by-budget
      document.querySelector('.selection-button[data-category="1-4-lakh"]').classList.add('active');
      displayCarSubsections('1-4-lakh', 'budget-car-subsections');

      // Display default category for electric-cars and latest-cars
      displayCarSubsections('electric-cars', 'electric-car-subsections');
      displayCarSubsections('latest-cars', 'latest-car-subsections');
    </script>
